# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Mock database of users
users_db = {
    "1": {"username": "john_doe", "email": "john@example.com", "role": "user", "account_status": "active", "subscription_tier": "free"},
    "2": {"username": "admin_user", "email": "admin@example.com", "role": "admin", "account_status": "active", "subscription_tier": "pro"}
}

# Dummy admin user for simplicity
current_user = {
    "user_id": "1",
    "role": "admin"
}

def requires_admin(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user["user_id"] != kwargs.get("user_id") or current_user["role"] != "admin":
            return jsonify({"error": "Access denied"}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<user_id>', methods=['PUT'])
@requires_admin
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({"error": "User not found"}), 404
    
    data = request.get_json()
    
    for key, value in data.items():
        if key in users_db[user_id]:
            users_db[user_id][key] = value
        else:
            return jsonify({"error": f"Invalid field: {key}"}), 400
    
    return jsonify(users_db[user_id]), 200

if __name__ == '__main__':
    app.run(debug=True)